const body = $input.first().json.body || $input.first().json;

const roleDescription = body.role_description || '';
const cvContent = body.cv_content || '';
const mcpServerUrl = body.mcp_server_url || 'http://localhost:8083';

if (!roleDescription.trim()) {
  return [{ json: { _error: true, message: 'role_description alanı zorunludur.' } }];
}
if (!cvContent.trim()) {
  return [{ json: { _error: true, message: 'cv_content alanı zorunludur.' } }];
}

if (roleDescription.length > 10000) {
  return [{ json: { _error: true, message: 'role_description 10.000 karakteri aşamaz.' } }];
}
if (cvContent.length > 30000) {
  return [{ json: { _error: true, message: 'cv_content 30.000 karakteri aşamaz.' } }];
}

return [{
  json: {
    _error: false,
    role_description: roleDescription.trim(),
    cv_content: cvContent.trim(),
    mcpServerUrl
  }
}];

const resp = $input.item.json;

// HTTP error veya MCP hatası kontrolü
if (resp.error || (resp.statusCode && resp.statusCode >= 400)) {
  const detail = resp.detail || resp.message || resp.error || 'MCP server hatası';
  return [{
    json: {
      success: false,
      error: detail,
      hint: 'MCP server çalışıyor mu? OPENAI_API_KEY veya AZURE_OPENAI_ENDPOINT ayarlanmış mı?'
    }
  }];
}

const score = resp.score ?? 0;
const verdict = resp.verdict || '';
const summary = resp.summary || '';
const strengths = resp.strengths || [];
const gaps = resp.gaps || [];
const recommendation = resp.recommendation || '';
const model = resp.model || '';
const provider = resp.provider || '';

// Skor rengi / etiketi
let scoreLabel = '';
if (score >= 85) scoreLabel = '🟢 Excellent Match';
else if (score >= 70) scoreLabel = '🔵 Good Match';
else if (score >= 50) scoreLabel = '🟡 Partial Match';
else if (score >= 25) scoreLabel = '🟠 Poor Match';
else scoreLabel = '🔴 Not Suitable';

return [{
  json: {
    success: true,
    score,
    score_label: scoreLabel,
    verdict,
    summary,
    strengths,
    gaps,
    recommendation,
    analyzed_by: { model, provider },
    analyzed_at: new Date().toISOString()
  }
}];
